const threshold = parseFloat($env.DROP_OFF_THRESHOLD_PCT || 30);
const steps = $input.all().map(i=>i.json).sort((a,b)=>parseInt(a.step_order)-parseInt(b.step_order));
const results = steps.map(s => {
  const started = parseInt(s.started||0);
  const completed = parseInt(s.completed||0);
  const drop_off_pct = started > 0 ? ((started-completed)/started*100).toFixed(1) : 0;
  const completion_rate = started > 0 ? (completed/started*100).toFixed(1) : 0;
  return { ...s, drop_off_pct: parseFloat(drop_off_pct), completion_rate: parseFloat(completion_rate), is_flagged: parseFloat(drop_off_pct) >= threshold };
});
const flagged = results.filter(r=>r.is_flagged);
const worst = results.reduce((a,b)=>a.drop_off_pct>b.drop_off_pct?a:b, results[0]||{});
return [{ json: { week: new Date().toISOString().slice(0,10), total_steps: results.length, flagged_count: flagged.length, threshold_pct: threshold, worst_step: worst, flagged, steps: results } }];

